(async()=>{try{
  var HOY=(function(){var t=(new Date()).getTimezoneOffset()*60000;return (new Date(Date.now()-t)).toISOString().split('T')[0];})();
  // Datos de contactos para que el lookup de aliado no rompa
  window.contactosData=[{id:'CON-09',nombre:'Ht Backpacker',tipo:'Agencia'},{id:'CON-25',nombre:'Rocio',tipo:'Aliado'}];
  // Una operacion dummy de HOY para que renderOperaciones llegue a pintar la seccion de pases
  window.operacionesData=[{id:'OP-DUMMY',fecha:HOY,estado:'Abierta',nombre_bote:'Dona Paty',id_bote:'B-1',destino:'Islas Ballestas',hora_salida:'08:00 AM',capacidad:10,ocupados:0,manifiesto:[],caja:[]}];
  window.cajaData=[];
  window.pasesExternosData=[
    {id:'PZ1',tipo:'Agencia',origenId:'CON-09',nombreOrigen:'Ht Backpacker',aliadoId:'Fran',pax:3,monto:69,adicionales:'',timestamp:Date.now()},
    {id:'PZ2',tipo:'Aliado(PaseIn)',origenId:'CON-25',nombreOrigen:'Rocio',aliadoId:'Fran',pax:2,monto:0,timestamp:Date.now()}
  ];
  // Activar la pestana operaciones (donde se pintan los pases)
  var tab=document.getElementById('tab-operaciones'); if(tab){document.querySelectorAll('.tab-content').forEach(function(t){t.classList.remove('active');}); tab.classList.add('active');}
  var cont=document.getElementById('operaciones-container'); if(cont){cont._fp=null;}
  renderOperaciones(window.operacionesData);
  await new Promise(function(r){setTimeout(r,600);});
  // Ocultar overlay de login (#sl-ov) para que el screenshot muestre los pases
  var ov=document.getElementById('sl-ov'); if(ov){ov.classList.add('sl-hide'); ov.style.display='none';}
  window.scrollTo(0,0);
  var sec=document.querySelector('[data-section="pases"]');
  var secExiste=!!sec;
  var filas=sec?[].slice.call(sec.querySelectorAll('tbody tr')):[];
  function rowInfo(idx){
    var f=filas[idx]; if(!f)return null;
    var txt=f.textContent.replace(/\s+/g,' ').trim();
    var btns=[].slice.call(f.querySelectorAll('button'));
    var cobrar=btns.find(function(b){return b.textContent.replace(/\s+/g,' ').indexOf('Cobrar')>=0;});
    return {txt:txt.slice(0,80), tieneCobrar:!!cobrar, cobrarTxt:cobrar?cobrar.textContent.replace(/\s+/g,' ').trim():null};
  }
  // localizar por contenido
  var agFila=null, alFila=null;
  filas.forEach(function(f){var t=f.textContent;if(t.indexOf('Ht Backpacker')>=0)agFila=f;if(t.indexOf('Rocio')>=0)alFila=f;});
  function infoDe(f){if(!f)return null;var btns=[].slice.call(f.querySelectorAll('button'));var c=btns.find(function(b){return b.textContent.replace(/\s+/g,' ').indexOf('Cobrar')>=0;});return {txt:f.textContent.replace(/\s+/g,' ').trim().slice(0,80),tieneCobrar:!!c,cobrarTxt:c?c.textContent.replace(/\s+/g,' ').trim():null};}
  var docEl=document.documentElement;
  return {ver:(window.APP_VERSION||null), secExiste:secExiste, nFilas:filas.length,
    agencia:infoDe(agFila), aliado:infoDe(alFila),
    overflowX:docEl.scrollWidth>window.innerWidth, sw:docEl.scrollWidth, iw:window.innerWidth};
}catch(e){return{crash:e.message,stack:(e.stack||'').slice(0,300)}}})()
